import { client } from '@/sanity/lib/client'
import { allPostsQuery } from '@/sanity/lib/queries'
import Image from 'next/image'
import Link from 'next/link'
import type { Metadata } from 'next'

export const revalidate = 60

export const metadata: Metadata = {
  title: 'Blog | The Prime Crafters',
  description:
    'Insights, strategies, and expert tips on AI automation, digital transformation, and business growth from The Prime Crafters team.',
  openGraph: {
    title: 'Blog | The Prime Crafters',
    description:
      'Insights, strategies, and expert tips on AI automation and business growth.',
    url: 'https://www.theprimecrafters.com/blog',
    siteName: 'PrimeCrafters',
    type: 'website',
  },
  twitter: {
    card: 'summary_large_image',
    title: 'Blog | The Prime Crafters',
    description:
      'Insights, strategies, and expert tips on AI automation and business growth.',
    site: '@PrimeCrafters',
  },
}

interface Post {
  _id: string
  title: string
  slug: { current: string }
  excerpt?: string
  publishedAt?: string
  readTime?: number
  category?: string
  mainImage?: {
    asset: { url: string }
    alt?: string
  }
  author?: {
    name: string
    image?: { asset: { url: string } }
  }
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })
}

export default async function BlogPage() {
  const posts: Post[] = await client.fetch(allPostsQuery)
  const [featured, ...rest] = posts ?? []

  return (
    <main className="blog-page">
      {/* ── Hero ── */}
      <section className="blog-hero">
        <div className="blog-hero__inner">
          <span className="blog-hero__eyebrow">Our Blog</span>
          <h1 className="blog-hero__title">
            Insights &amp; <span className="blog-hero__accent">Resources</span>
          </h1>
          <p className="blog-hero__subtitle">
            Expert tips, industry insights, and behind-the-scenes from The
            Prime&nbsp;Crafters team — helping you stay ahead in the age of AI.
          </p>
        </div>
      </section>

      <div className="blog-container">
        {!posts || posts.length === 0 ? (
          <div className="blog-empty">
            <div className="blog-empty__icon">✦</div>
            <p className="blog-empty__text">No posts published yet. Check back soon!</p>
          </div>
        ) : (
          <>
            {/* ── Featured post ── */}
            {featured && (
              <Link href={`/blog/${featured.slug.current}`} className="blog-featured">
                <div className="blog-featured__image-wrap">
                  {featured.mainImage?.asset?.url ? (
                    <Image
                      src={featured.mainImage.asset.url}
                      alt={featured.mainImage.alt ?? featured.title}
                      fill
                      className="blog-featured__img"
                      priority
                    />
                  ) : (
                    <div className="blog-featured__placeholder" aria-hidden="true">
                      <span>✦</span>
                    </div>
                  )}
                  {featured.category && (
                    <span className="blog-tag blog-tag--overlay">{featured.category}</span>
                  )}
                </div>

                <div className="blog-featured__body">
                  <span className="blog-featured__label">Featured</span>
                  <h2 className="blog-featured__title">{featured.title}</h2>
                  {featured.excerpt && (
                    <p className="blog-featured__excerpt">{featured.excerpt}</p>
                  )}
                  <div className="blog-featured__meta">
                    {featured.author && (
                      <div className="blog-author">
                        {featured.author.image?.asset?.url && (
                          <Image
                            src={featured.author.image.asset.url}
                            alt={featured.author.name}
                            width={32}
                            height={32}
                            className="blog-author__avatar"
                          />
                        )}
                        <span className="blog-author__name">{featured.author.name}</span>
                      </div>
                    )}
                    <div className="blog-meta-right">
                      {featured.publishedAt && (
                        <span className="blog-meta__date">
                          {formatDate(featured.publishedAt)}
                        </span>
                      )}
                      {featured.readTime && (
                        <span className="blog-meta__read">{featured.readTime} min read</span>
                      )}
                    </div>
                  </div>
                  <span className="blog-featured__cta">
                    Read article <span aria-hidden="true">→</span>
                  </span>
                </div>
              </Link>
            )}

            {/* ── Post grid ── */}
            {rest.length > 0 && (
              <section className="blog-grid-section">
                <h2 className="blog-grid-section__heading">Latest Posts</h2>
                <div className="blog-grid">
                  {rest.map((post) => (
                    <Link
                      key={post._id}
                      href={`/blog/${post.slug.current}`}
                      className="blog-card"
                    >
                      <div className="blog-card__image-wrap">
                        {post.mainImage?.asset?.url ? (
                          <Image
                            src={post.mainImage.asset.url}
                            alt={post.mainImage.alt ?? post.title}
                            fill
                            className="blog-card__img"
                          />
                        ) : (
                          <div className="blog-card__placeholder" aria-hidden="true">
                            <span>✦</span>
                          </div>
                        )}
                        {post.category && (
                          <span className="blog-tag blog-tag--overlay">{post.category}</span>
                        )}
                      </div>

                      <div className="blog-card__body">
                        <h3 className="blog-card__title">{post.title}</h3>
                        {post.excerpt && (
                          <p className="blog-card__excerpt">{post.excerpt}</p>
                        )}
                        <div className="blog-card__footer">
                          {post.author && (
                            <div className="blog-author blog-author--sm">
                              {post.author.image?.asset?.url && (
                                <Image
                                  src={post.author.image.asset.url}
                                  alt={post.author.name}
                                  width={24}
                                  height={24}
                                  className="blog-author__avatar"
                                />
                              )}
                              <span className="blog-author__name">{post.author.name}</span>
                            </div>
                          )}
                          <div className="blog-meta-right">
                            {post.publishedAt && (
                              <span className="blog-meta__date">
                                {formatDate(post.publishedAt)}
                              </span>
                            )}
                            {post.readTime && (
                              <span className="blog-meta__read">{post.readTime} min</span>
                            )}
                          </div>
                        </div>
                      </div>
                    </Link>
                  ))}
                </div>
              </section>
            )}
          </>
        )}
      </div>
    </main>
  )
}